    def _connect(self):
        """Establish connection to Kafka cluster using environment-based config."""
        if self._connected and self._admin_client is not None:
            return

        try:
            from kafka.admin import KafkaAdminClient
        except ImportError:
            logger.error(
                "kafka-python is not installed. Install it with: "
                "pip install kafka-python"
            )
            sys.exit(1)

        bootstrap_servers = get_bootstrap_servers()
        sasl_config = get_sasl_config()

        try:
            self._admin_client = KafkaAdminClient(
                bootstrap_servers=bootstrap_servers,
                client_id='kafka-admin-tool',
                **sasl_config
            )
            self._connected = True
            logger.info("Connected to Kafka cluster successfully.")
        except Exception as e:
            logger.error(f"Failed to connect to Kafka cluster: {e}")
            sys.exit(1)

    def _disconnect(self):
        """Close the admin client connection."""
        if self._admin_client is not None:
            try:
                self._admin_client.close()
            except Exception as e:
                logger.warning(f"Error closing admin client: {e}")
            finally:
                self._admin_client = None
                self._connected = False

    def __enter__(self):
        self._connect()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self._disconnect()
        return False

    def create_topics(
        self,
        topics: List[Dict],
    ) -> Dict[str, str]:
        """
        Create one or more topics.

        Args:
            topics: List of dicts with keys:
                - name (str): Topic name
                - num_partitions (int): Number of partitions
                - replication_factor (int): Replication factor
                - config (dict, optional): Topic-level configuration overrides

        Returns:
            Dict mapping topic name to result status.
        """
        self._connect()

        from kafka.admin import NewTopic

        new_topics = []
        for topic_spec in topics:
            name = topic_spec['name']
            num_partitions = topic_spec.get('num_partitions', 1)
            replication_factor = topic_spec.get('replication_factor', 1)
            topic_config = topic_spec.get('config', {})

            # Validate topic name
            if not name or not isinstance(name, str):
                logger.error(f"Invalid topic name: {name}")
                continue

            # Validate numeric parameters
            if num_partitions < 1:
                logger.error(f"num_partitions must be >= 1 for topic '{name}'")
                continue
            if replication_factor < 1:
                logger.error(f"replication_factor must be >= 1 for topic '{name}'")
                continue

            nt = NewTopic(
                name=name,
                num_partitions=num_partitions,
                replication_factor=replication_factor,
                topic_configs=topic_config
            )
            new_topics.append(nt)

        if not new_topics:
            logger.warning("No valid topics to create.")
            return {}

        results = {}
        try:
            response = self._admin_client.create_topics(
                new_topics=new_topics,
                validate_only=False
            )
            for topic in new_topics:
                results[topic.name] = "created"
            logger.info(f"Topics created successfully: {list(results.keys())}")
        except Exception as e:
            error_msg = str(e)
            logger.error(f"Error creating topics: {error_msg}")
            for topic in new_topics:
                results[topic.name] = f"error: {error_msg}"

        return results

