def parse_config_string(config_str: str) -> Dict[str, str]:
    """
    Parse a configuration string in the format 'key1=value1,key2=value2'.

    Args:
        config_str: Configuration string.

    Returns:
        Dict of configuration key-value pairs.
    """
    config = {}
    if not config_str:
        return config

    for pair in config_str.split(','):
        pair = pair.strip()
        if '=' in pair:
            key, value = pair.split('=', 1)
            config[key.strip()] = value.strip()
        else:
            logger.warning(f"Ignoring invalid config pair: '{pair}'")

    return config


def parse_topic_spec(spec_str: str) -> Dict:
    """
    Parse a topic specification string.
    Format: 'name:partitions:replication_factor' or just 'name'.

    Args:
        spec_str: Topic specification string.

    Returns:
        Dict with topic specification.
    """
    parts = spec_str.split(':')
    spec = {
        'name': parts[0].strip(),
        'num_partitions': 1,
        'replication_factor': 1,
    }

    if len(parts) >= 2:
        try:
            spec['num_partitions'] = int(parts[1])
        except ValueError:
            logger.warning(
                f"Invalid partition count '{parts[1]}', using default 1"
            )

    if len(parts) >= 3:
        try:
            spec['replication_factor'] = int(parts[2])
        except ValueError:
            logger.warning(
                f"Invalid replication factor '{parts[2]}', using default 1"
            )

    return spec


