def cmd_create_topic(admin: KafkaAdminWrapper, args) -> int:
    """Handle create-topic command."""
    topic_config = parse_config_string(args.config)

    topics = []
    for topic_str in args.topics:
        spec = parse_topic_spec(topic_str)
        if topic_config:
            spec['config'] = topic_config
        topics.append(spec)

    results = admin.create_topics(topics)

    for topic_name, status in results.items():
        print(f"  {topic_name}: {status}")

    has_errors = any('error' in str(v).lower() for v in results.values())
    return 1 if has_errors else 0


