def cmd_batch_create(admin: KafkaAdminWrapper, args) -> int:
    """Handle batch-create command."""
    file_path = args.file

    if not os.path.isfile(file_path):
        print(f"File not found: {file_path}")
        return 1

    try:
        with open(file_path, 'r') as f:
            topics_spec = json.load(f)
    except json.JSONDecodeError as e:
        print(f"Invalid JSON in file '{file_path}': {e}")
        return 1
    except IOError as e:
        print(f"Error reading file '{file_path}': {e}")
        return 1

    if not isinstance(topics_spec, list):
        print("JSON file must contain a list of topic specifications.")
        return 1

    # Validate each topic spec
    validated_topics = []
    for i, spec in enumerate(topics_spec):
        if not isinstance(spec, dict):
            print(f"Skipping invalid entry at index {i}: not a dict")
            continue
        if 'name' not in spec:
            print(f"Skipping entry at index {i}: missing 'name' field")
            continue

        topic = {
            'name': spec['name'],
            'num_partitions': spec.get('num_partitions', 1),
            'replication_factor': spec.get('replication_factor', 1),
        }
        if 'config' in spec and isinstance(spec['config'], dict):
            # Ensure all config values are strings
            topic['config'] = {
                str(k): str(v) for k, v in spec['config'].items()
            }
        validated_topics.append(topic)

    if not validated_topics:
        print("No valid topic specifications found in file.")
        return 1

    print(f"Creating {len(validated_topics)} topics from '{file_path}'...")
    results = admin.create_topics(validated_topics)

    for topic_name, status in results.items():
        print(f"  {topic_name}: {status}")

    has_errors = any('error' in str(v).lower() for v in results.values())
    return 1 if has_errors else 0


COMMAND_HANDLERS = {
    'create-topic': cmd_create_topic,
    'delete-topic': cmd_delete_topic,
    'list-topics': cmd_list_topics,
    'describe-topic': cmd_describe_topic,
    'add-partitions': cmd_add_partitions,
    'get-config': cmd_get_config,
    'set-config': cmd_set_config,
    'describe-cluster': cmd_describe_cluster,
    'list-consumer-groups': cmd_list_consumer_groups,
    'batch-create': cmd_batch_create,
}


def main():
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    handler = COMMAND_HANDLERS.get(args.command)
    if handler is None:
        print(f"Unknown command: {args.command}")
        parser.print_help()
        sys.exit(1)

    with KafkaAdminWrapper() as admin:
        exit_code = handler(admin, args)

    sys.exit(exit_code)


if __name__ == '__main__':
    main()